#!/usr/bin/env node
/**
 * Generates the CA bundle TypeScript module.
 *
 * If CA_BUNDLE_URL env var is set, downloads from that URL.
 * If CA_BUNDLE_HOST env var is set, extracts the CA chain from that host.
 * Otherwise: generates an empty bundle (extension works via system CAs).
 */

const https = require('https');
const tls = require('tls');
const fs = require('fs');
const path = require('path');

const CA_BUNDLE_URL = process.env.CA_BUNDLE_URL || '';
const CA_BUNDLE_HOST = process.env.CA_BUNDLE_HOST || '';
const OUTPUT_DIR = path.join(__dirname, '..', 'src', 'generated');
const OUTPUT_FILE = path.join(OUTPUT_DIR, 'ca-bundle.ts');

function fetchUrl(url, timeoutMs = 10000) {
  return new Promise((resolve) => {
    const req = https.get(url, { timeout: timeoutMs, rejectUnauthorized: false }, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        fetchUrl(res.headers.location, timeoutMs).then(resolve);
        res.resume();
        return;
      }
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve(data));
    });
    req.on('error', () => resolve(''));
    req.on('timeout', () => { req.destroy(); resolve(''); });
  });
}

function extractCertsFromServer(host, port = 443) {
  return new Promise((resolve) => {
    const socket = tls.connect({ host, port, rejectUnauthorized: false }, () => {
      const cert = socket.getPeerCertificate(true);
      const pems = [];
      let current = cert;
      const seen = new Set();
      while (current && current.raw && !seen.has(current.fingerprint256)) {
        seen.add(current.fingerprint256);
        const b64 = current.raw.toString('base64');
        const lines = b64.match(/.{1,64}/g) || [];
        pems.push('-----BEGIN CERTIFICATE-----\n' + lines.join('\n') + '\n-----END CERTIFICATE-----');
        current = current.issuerCertificate;
        if (current === cert) break;
      }
      socket.end();
      resolve(pems.slice(1).join('\n'));
    });
    socket.on('error', () => resolve(''));
    socket.setTimeout(10000, () => { socket.destroy(); resolve(''); });
  });
}

async function main() {
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
  let pem = '';

  if (CA_BUNDLE_URL) {
    console.log('Fetching CA bundle from ' + CA_BUNDLE_URL + '...');
    pem = await fetchUrl(CA_BUNDLE_URL);
  }
  if ((!pem || pem.trim().length < 100) && CA_BUNDLE_HOST) {
    console.log('Extracting CA chain from ' + CA_BUNDLE_HOST + '...');
    pem = await extractCertsFromServer(CA_BUNDLE_HOST);
  }
  if (!pem || pem.trim().length < 100) {
    console.log('No CA bundle configured. Using empty bundle (system CAs will be used).');
    pem = '';
  }

  const content = [
    '// AUTO-GENERATED by scripts/fetch-ca-bundle.js — do not edit manually.',
    '// Custom CA certificates for TLS trust.',
    'export const CA_BUNDLE = `',
    pem,
    '`;',
    '',
  ].join('\n');

  fs.writeFileSync(OUTPUT_FILE, content);
  console.log(`CA bundle written (${pem ? pem.split('\n').length : 0} lines)`);
}

main().catch((err) => {
  console.error('fetch-ca-bundle failed:', err.message);
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
  fs.writeFileSync(OUTPUT_FILE, 'export const CA_BUNDLE = ``;\n');
  process.exit(0);
});
